from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Find the main subject (likely an airport)
    main_subject = None
    for subject in subject_map.keys():
        if "Airport" in subject or "Airport" in subject.split():
            main_subject = subject
            break
    if not main_subject:
        main_subject = list(subject_map.keys())[0] if subject_map else ""

    # Collect information for building one complex sentence
    clauses = []
    location_info = None
    country_info = None
    language_info = None
    city_served_info = None
    other_clauses = []

    # First pass: extract key relationships and build hierarchy
    for subject, triples_list in subject_map.items():
        for predicate, obj in triples_list:
            if predicate == "cityServed":
                city_served_info = obj
            elif predicate == "location":
                location_info = obj
            elif predicate == "country":
                if location_info and subject == location_info:
                    country_info = obj
                elif subject == main_subject:
                    country_info = obj
            elif predicate == "isPartOf":
                clauses.append(f"is part of {obj}")
            elif predicate == "language" or predicate == "officialLanguage":
                language_info = obj
            elif predicate == "capital":
                clauses.append(f"has {obj} as its capital")
            elif predicate == "operatingOrganisation":
                clauses.append(f"is operated by {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                clauses.append(f"is {obj} metres above sea level")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                clauses.append(f"is {obj} feet above sea level")
            elif predicate == "elevationAboveTheSeaLevelInMetres":
                clauses.append(f"is {obj} metres above sea level")
            elif predicate == "runwayLength":
                clauses.append(f"has a runway length of {obj} metres")
            elif predicate == "runwayName":
                clauses.append(f"has a runway named {obj}")
            elif predicate == "runwaySurfaceType":
                clauses.append(f"has a runway surface type of {obj}")
            elif predicate == "1stRunwayLengthFeet":
                clauses.append(f"has a first runway length of {obj} feet")
            elif predicate == "1stRunwaySurfaceType":
                clauses.append(f"has a first runway with {obj} surface")
            elif predicate == "3rdRunwayLengthFeet":
                clauses.append(f"has a third runway length of {obj} feet")
            elif predicate == "icaoLocationIdentifier":
                clauses.append(f"has an ICAO location identifier of {obj}")
            elif predicate == "iataLocationIdentifier":
                clauses.append(f"has an IATA location identifier of {obj}")
            elif predicate == "locationIdentifier":
                clauses.append(f"has a location identifier of {obj}")
            elif predicate == "nativeName":
                clauses.append(f"has a native name of {obj}")
            elif predicate == "owner":
                clauses.append(f"is owned by {obj}")
            elif predicate == "mayor":
                clauses.append(f"has a mayor of {obj}")
            elif predicate == "leader":
                clauses.append(f"has {obj} as its leader")
            elif predicate == "leaderParty":
                clauses.append(f"has a leader party of {obj}")
            elif predicate == "headquarter":
                clauses.append(f"has its headquarters in {obj}")
            else:
                other_clauses.append(f"has a {predicate} of {obj}")

    # Build the main sentence structure with proper hierarchy
    if not main_subject:
        return "."

    result = main_subject

    # Add city served information
    if city_served_info:
        result += f" serves the city of {city_served_info}"

    # Add location-based information with proper hierarchy
    if location_info:
        if not city_served_info:  # Only add "is located in" if not already covered by cityServed
            result += f" is located in {location_info}"
        if country_info:
            result += f", which is in {country_info}"
        if language_info:
            # Handle language properly: "where [language] is spoken"
            language_clean = language_info.replace(" language", "") if "language" in language_info.lower() else language_info
            result += f", where {language_clean} is spoken"
    elif country_info and not city_served_info:
        result += f" is located in {country_info}"
        if language_info:
            language_clean = language_info.replace(" language", "") if "language" in language_info.lower() else language_info
            result += f", where {language_clean} is spoken"

    # Add other clauses (e.g., elevation, runway info, etc.)
    all_clauses = clauses + other_clauses
    if all_clauses:
        result += " and " + ", ".join(all_clauses)

    return result + "."

